class Solution:
    def solve(self, nums: list[int], target: int) -> bool:
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] == target:
                return True
            elif nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return False

if __name__ == '__main__':
    solver = Solution()
    for _ in range(int(input())):
        n = int(input())
        nums = list(map(int, input().split()))
        target = int(input())
        print(solver.solve(nums, target))

