class Solution {public:
bool solve(vector<int>& nums, int target) {
    int left = 0, right = nums.size() - 1;
    while (left <= right) {
        int mid = (left + right) / 2;
        if (nums[mid] == target) return true;
        else if (nums[mid] < target) left = mid + 1;
        else right = mid - 1;
    }
    return false;
}    

int main() {
    int t;
    cin >> t;
    Solution s;
    while(t-- > 0) {
        int n;
        cin >> n;
        vector<int> nums(n);
        for (int i = 0; i < n; i++) {
            cin >> nums[i];
        }
        int target;
        cin >> target;
        cout << (s.solve(nums, target) ? "YES" : "NO") << endl;
    }
    return 0;
}
